CREATE TABLE IF NOT EXISTS default.ontime_v2
(
    `FlightDate` Date COMMENT 'Flight Date (yyyymmdd)' CODEC(DoubleDelta, ZSTD(1)),
    `Year` UInt16 ALIAS toYear(FlightDate) COMMENT 'Calendar year for the flight date. In ontime_v2 this is a derived alias computed from FlightDate rather than a separately stored source field.',
    `Quarter` UInt8 ALIAS toQuarter(FlightDate) COMMENT 'Calendar quarter for the flight date, numbered 1 through 4. In ontime_v2 this is a derived alias computed from FlightDate.',
    `Month` UInt8 ALIAS toMonth(FlightDate) COMMENT 'Calendar month for the flight date, numbered 1 through 12. In ontime_v2 this is a derived alias computed from FlightDate.',
    `DayofMonth` UInt8 ALIAS toDayOfMonth(FlightDate) COMMENT 'Day of the month for the flight date, numbered 1 through 31. In ontime_v2 this is a derived alias computed from FlightDate.',
    `DayOfWeek` UInt8 ALIAS toDayOfWeek(FlightDate) COMMENT 'Day of week for the flight date. In ontime_v2 this is a derived alias computed from FlightDate using ClickHouse toDayOfWeek semantics.',
    `Reporting_Airline` LowCardinality(String) COMMENT 'Unique Carrier Code. When the same code has been used by multiple carriers, a numeric suffix is used for earlier users, for example, PA, PA(1), PA(2). Use this field for analysis across a range of years.',
    `UniqueCarrier` LowCardinality(String) ALIAS Reporting_Airline COMMENT 'Legacy compatibility alias for Reporting_Airline. This exposes the BTS unique carrier code under the historical ontime column name for cross-year airline analysis.',
    `DOT_ID_Reporting_Airline` UInt32 COMMENT 'An identification number assigned by US DOT to identify a unique airline (carrier). A unique airline (carrier) is defined as one holding and reporting under the same DOT certificate regardless of its Code, Name, or holding company/corporation.' CODEC(ZSTD(1)),
    `AirlineID` UInt32 ALIAS DOT_ID_Reporting_Airline COMMENT 'Legacy compatibility alias for DOT_ID_Reporting_Airline. This is the DOT-assigned airline identifier preserved under the historical ontime column name.',
    `IATA_CODE_Reporting_Airline` LowCardinality(String) COMMENT 'Code assigned by IATA and commonly used to identify a carrier. As the same code may have been assigned to different carriers over time, the code is not always unique. For analysis, use the Unique Carrier Code.',
    `Carrier` LowCardinality(String) ALIAS IATA_CODE_Reporting_Airline COMMENT 'Legacy compatibility alias for IATA_CODE_Reporting_Airline. This exposes the carrier code commonly used in public schedules, but it is not stable enough for long-range historical analysis.',
    `Tail_Number` LowCardinality(String) COMMENT 'Tail Number',
    `TailNum` LowCardinality(String) ALIAS Tail_Number COMMENT 'Legacy compatibility alias for Tail_Number. This preserves the historical ontime column name for the aircraft registration or tail number.',
    `Flight_Number_Reporting_Airline` LowCardinality(String) COMMENT 'Flight Number',
    `FlightNum` LowCardinality(String) ALIAS Flight_Number_Reporting_Airline COMMENT 'Legacy compatibility alias for Flight_Number_Reporting_Airline. This preserves the historical ontime column name for the published flight number.',
    `OriginAirportID` UInt32 COMMENT 'Origin Airport, Airport ID. An identification number assigned by US DOT to identify a unique airport. Use this field for airport analysis across a range of years because an airport can change its airport code and airport codes can be reused.' CODEC(ZSTD(1)),
    `OriginAirportSeqID` UInt32 COMMENT 'Origin Airport, Airport Sequence ID. An identification number assigned by US DOT to identify a unique airport at a given point of time. Airport attributes, such as airport name or coordinates, may change over time.' CODEC(ZSTD(1)),
    `OriginCityMarketID` UInt32 COMMENT 'Origin Airport, City Market ID. City Market ID is an identification number assigned by US DOT to identify a city market. Use this field to consolidate airports serving the same city market.' CODEC(ZSTD(1)),
    `Origin` LowCardinality(String) COMMENT 'Origin Airport',
    `OriginCityName` LowCardinality(String) COMMENT 'Origin Airport, City Name',
    `OriginState` LowCardinality(String) COMMENT 'Origin Airport, State Code',
    `OriginStateFips` LowCardinality(String) COMMENT 'Origin Airport, State Fips',
    `OriginStateName` LowCardinality(String) COMMENT 'Origin Airport, State Name',
    `OriginWac` UInt32 COMMENT 'Origin Airport, World Area Code' CODEC(ZSTD(1)),
    `DestAirportID` UInt32 COMMENT 'Destination Airport, Airport ID. An identification number assigned by US DOT to identify a unique airport. Use this field for airport analysis across a range of years because an airport can change its airport code and airport codes can be reused.' CODEC(ZSTD(1)),
    `DestAirportSeqID` UInt32 COMMENT 'Destination Airport, Airport Sequence ID. An identification number assigned by US DOT to identify a unique airport at a given point of time. Airport attributes, such as airport name or coordinates, may change over time.' CODEC(ZSTD(1)),
    `DestCityMarketID` UInt32 COMMENT 'Destination Airport, City Market ID. City Market ID is an identification number assigned by US DOT to identify a city market. Use this field to consolidate airports serving the same city market.' CODEC(ZSTD(1)),
    `Dest` LowCardinality(String) COMMENT 'Destination Airport',
    `DestCityName` LowCardinality(String) COMMENT 'Destination Airport, City Name',
    `DestState` LowCardinality(String) COMMENT 'Destination Airport, State Code',
    `DestStateFips` LowCardinality(String) COMMENT 'Destination Airport, State Fips',
    `DestStateName` LowCardinality(String) COMMENT 'Destination Airport, State Name',
    `DestWac` UInt32 COMMENT 'Destination Airport, World Area Code' CODEC(ZSTD(1)),
    `CRSDepTime` Nullable(UInt16) COMMENT 'CRS Departure Time (local time: hhmm)' CODEC(ZSTD(1)),
    `DepTime` Nullable(UInt16) COMMENT 'Actual Departure Time (local time: hhmm)' CODEC(ZSTD(1)),
    `DepDelay` Nullable(Int32) COMMENT 'Difference in minutes between scheduled and actual departure time. Early departures show negative numbers.' CODEC(ZSTD(1)),
    `DepDelayMinutes` Nullable(UInt16) COMMENT 'Difference in minutes between scheduled and actual departure time. Early departures set to 0.' CODEC(ZSTD(1)),
    `DepDel15` UInt8 COMMENT 'Departure Delay Indicator, 15 Minutes or More (1=Yes)',
    `DepartureDelayGroups` Nullable(Int8) COMMENT 'Departure Delay intervals, every (15 minutes from <-15 to >180)' CODEC(ZSTD(1)),
    `DepTimeBlk` LowCardinality(String) COMMENT 'CRS Departure Time Block, Hourly Intervals',
    `TaxiOut` Nullable(UInt16) COMMENT 'Taxi Out Time, in Minutes' CODEC(ZSTD(1)),
    `WheelsOff` Nullable(UInt16) COMMENT 'Wheels Off Time (local time: hhmm)' CODEC(ZSTD(1)),
    `WheelsOn` Nullable(UInt16) COMMENT 'Wheels On Time (local time: hhmm)' CODEC(ZSTD(1)),
    `TaxiIn` Nullable(UInt16) COMMENT 'Taxi In Time, in Minutes' CODEC(ZSTD(1)),
    `CRSArrTime` Nullable(UInt16) COMMENT 'CRS Arrival Time (local time: hhmm)' CODEC(ZSTD(1)),
    `ArrTime` Nullable(UInt16) COMMENT 'Actual Arrival Time (local time: hhmm)' CODEC(ZSTD(1)),
    `ArrDelay` Nullable(Int32) COMMENT 'Difference in minutes between scheduled and actual arrival time. Early arrivals show negative numbers.' CODEC(ZSTD(1)),
    `ArrDelayMinutes` Nullable(UInt16) COMMENT 'Difference in minutes between scheduled and actual arrival time. Early arrivals set to 0.' CODEC(ZSTD(1)),
    `ArrDel15` UInt8 COMMENT 'Arrival Delay Indicator, 15 Minutes or More (1=Yes)',
    `ArrivalDelayGroups` Nullable(Int8) COMMENT 'Arrival Delay intervals, every (15 minutes from <-15 to >180)' CODEC(ZSTD(1)),
    `ArrTimeBlk` LowCardinality(String) COMMENT 'CRS Arrival Time Block, Hourly Intervals',
    `Cancelled` UInt8 COMMENT 'Cancelled Flight Indicator (1=Yes)',
    `CancellationCode` LowCardinality(String) COMMENT 'Specifies The Reason For Cancellation',
    `Diverted` UInt8 COMMENT 'Diverted Flight Indicator (1=Yes)',
    `CRSElapsedTime` Nullable(Int32) COMMENT 'CRS Elapsed Time of Flight, in Minutes' CODEC(ZSTD(1)),
    `ActualElapsedTime` Nullable(Int32) COMMENT 'Elapsed Time of Flight, in Minutes' CODEC(ZSTD(1)),
    `AirTime` Nullable(Int32) COMMENT 'Flight Time, in Minutes' CODEC(ZSTD(1)),
    `Flights` UInt8 COMMENT 'Number of Flights',
    `Distance` Nullable(UInt16) COMMENT 'Distance between airports (miles)' CODEC(ZSTD(1)),
    `DistanceGroup` UInt8 COMMENT 'Distance Intervals, every 250 Miles, for Flight Segment',
    `CarrierDelay` Nullable(UInt16) COMMENT 'Carrier Delay, in Minutes' CODEC(ZSTD(1)),
    `WeatherDelay` Nullable(UInt16) COMMENT 'Weather Delay, in Minutes' CODEC(ZSTD(1)),
    `NASDelay` Nullable(UInt16) COMMENT 'National Air System Delay, in Minutes' CODEC(ZSTD(1)),
    `SecurityDelay` Nullable(UInt16) COMMENT 'Security Delay, in Minutes' CODEC(ZSTD(1)),
    `LateAircraftDelay` Nullable(UInt16) COMMENT 'Late Aircraft Delay, in Minutes' CODEC(ZSTD(1)),
    `FirstDepTime` Nullable(UInt16) COMMENT 'First Gate Departure Time at Origin Airport' CODEC(ZSTD(1)),
    `TotalAddGTime` Nullable(Int32) COMMENT 'Total Ground Time Away from Gate for Gate Return or Cancelled Flight' CODEC(ZSTD(1)),
    `LongestAddGTime` Nullable(Int32) COMMENT 'Longest Time Away from Gate for Gate Return or Cancelled Flight' CODEC(ZSTD(1)),
    `DivAirportLandings` Nullable(UInt8) COMMENT 'Number of Diverted Airport Landings',
    `DivReachedDest` UInt8 COMMENT 'Destination Airport Reached or Not (1=Yes)',
    `DivActualElapsedTime` Nullable(Int32) COMMENT 'Elapsed Time of Diverted Flight, in Minutes' CODEC(ZSTD(1)),
    `DivArrDelay` Nullable(Int32) COMMENT 'Arrival Delay of a Diverted Flight' CODEC(ZSTD(1)),
    `DivDistance` Nullable(UInt16) COMMENT 'Distance between scheduled airport and final diverted airport (miles)' CODEC(ZSTD(1)),
    `Div1Airport` LowCardinality(String) COMMENT 'Diverted Airport Code1',
    `Div1AirportID` UInt32 COMMENT 'Airport ID of Diverted Airport 1. Airport ID is a Unique Key for an Airport' CODEC(ZSTD(1)),
    `Div1AirportSeqID` UInt32 COMMENT 'Airport Sequence ID of Diverted Airport 1. Unique Key for Time Specific Information for an Airport' CODEC(ZSTD(1)),
    `Div1WheelsOn` Nullable(UInt16) COMMENT 'Wheels On Time (local time: hhmm) at Diverted Airport Code1' CODEC(ZSTD(1)),
    `Div1TotalGTime` Nullable(Int32) COMMENT 'Total Ground Time Away from Gate at Diverted Airport Code1' CODEC(ZSTD(1)),
    `Div1LongestGTime` Nullable(Int32) COMMENT 'Longest Ground Time Away from Gate at Diverted Airport Code1' CODEC(ZSTD(1)),
    `Div1WheelsOff` Nullable(UInt16) COMMENT 'Wheels Off Time (local time: hhmm) at Diverted Airport Code1' CODEC(ZSTD(1)),
    `Div1TailNum` LowCardinality(String) COMMENT 'Aircraft Tail Number for Diverted Airport Code1',
    `Div2Airport` LowCardinality(String) COMMENT 'Diverted Airport Code2',
    `Div2AirportID` UInt32 COMMENT 'Airport ID of Diverted Airport 2. Airport ID is a Unique Key for an Airport' CODEC(ZSTD(1)),
    `Div2AirportSeqID` UInt32 COMMENT 'Airport Sequence ID of Diverted Airport 2. Unique Key for Time Specific Information for an Airport' CODEC(ZSTD(1)),
    `Div2WheelsOn` Nullable(UInt16) COMMENT 'Wheels On Time (local time: hhmm) at Diverted Airport Code2' CODEC(ZSTD(1)),
    `Div2TotalGTime` Nullable(Int32) COMMENT 'Total Ground Time Away from Gate at Diverted Airport Code2' CODEC(ZSTD(1)),
    `Div2LongestGTime` Nullable(Int32) COMMENT 'Longest Ground Time Away from Gate at Diverted Airport Code2' CODEC(ZSTD(1)),
    `Div2WheelsOff` Nullable(UInt16) COMMENT 'Wheels Off Time (local time: hhmm) at Diverted Airport Code2' CODEC(ZSTD(1)),
    `Div2TailNum` LowCardinality(String) COMMENT 'Aircraft Tail Number for Diverted Airport Code2',
    `Div3Airport` LowCardinality(String) COMMENT 'Diverted Airport Code3',
    `Div3AirportID` UInt32 COMMENT 'Airport ID of Diverted Airport 3. Airport ID is a Unique Key for an Airport' CODEC(ZSTD(1)),
    `Div3AirportSeqID` UInt32 COMMENT 'Airport Sequence ID of Diverted Airport 3. Unique Key for Time Specific Information for an Airport' CODEC(ZSTD(1)),
    `Div3WheelsOn` Nullable(UInt16) COMMENT 'Wheels On Time (local time: hhmm) at Diverted Airport Code3' CODEC(ZSTD(1)),
    `Div3TotalGTime` Nullable(Int32) COMMENT 'Total Ground Time Away from Gate at Diverted Airport Code3' CODEC(ZSTD(1)),
    `Div3LongestGTime` Nullable(Int32) COMMENT 'Longest Ground Time Away from Gate at Diverted Airport Code3' CODEC(ZSTD(1)),
    `Div3WheelsOff` Nullable(UInt16) COMMENT 'Wheels Off Time (local time: hhmm) at Diverted Airport Code3' CODEC(ZSTD(1)),
    `Div3TailNum` LowCardinality(String) COMMENT 'Aircraft Tail Number for Diverted Airport Code3',
    `Div4Airport` LowCardinality(String) COMMENT 'Diverted Airport Code4',
    `Div4AirportID` UInt32 COMMENT 'Airport ID of Diverted Airport 4. Airport ID is a Unique Key for an Airport' CODEC(ZSTD(1)),
    `Div4AirportSeqID` UInt32 COMMENT 'Airport Sequence ID of Diverted Airport 4. Unique Key for Time Specific Information for an Airport' CODEC(ZSTD(1)),
    `Div4WheelsOn` Nullable(UInt16) COMMENT 'Wheels On Time (local time: hhmm) at Diverted Airport Code4' CODEC(ZSTD(1)),
    `Div4TotalGTime` Nullable(Int32) COMMENT 'Total Ground Time Away from Gate at Diverted Airport Code4' CODEC(ZSTD(1)),
    `Div4LongestGTime` Nullable(Int32) COMMENT 'Longest Ground Time Away from Gate at Diverted Airport Code4' CODEC(ZSTD(1)),
    `Div4WheelsOff` Nullable(UInt16) COMMENT 'Wheels Off Time (local time: hhmm) at Diverted Airport Code4' CODEC(ZSTD(1)),
    `Div4TailNum` LowCardinality(String) COMMENT 'Aircraft Tail Number for Diverted Airport Code4',
    `Div5Airport` LowCardinality(String) COMMENT 'Diverted Airport Code5',
    `Div5AirportID` UInt32 COMMENT 'Airport ID of Diverted Airport 5. Airport ID is a Unique Key for an Airport' CODEC(ZSTD(1)),
    `Div5AirportSeqID` UInt32 COMMENT 'Airport Sequence ID of Diverted Airport 5. Unique Key for Time Specific Information for an Airport' CODEC(ZSTD(1)),
    `Div5WheelsOn` Nullable(UInt16) COMMENT 'Wheels On Time (local time: hhmm) at Diverted Airport Code5' CODEC(ZSTD(1)),
    `Div5TotalGTime` Nullable(Int32) COMMENT 'Total Ground Time Away from Gate at Diverted Airport Code5' CODEC(ZSTD(1)),
    `Div5LongestGTime` Nullable(Int32) COMMENT 'Longest Ground Time Away from Gate at Diverted Airport Code5' CODEC(ZSTD(1)),
    `Div5WheelsOff` Nullable(UInt16) COMMENT 'Wheels Off Time (local time: hhmm) at Diverted Airport Code5' CODEC(ZSTD(1)),
    `Div5TailNum` LowCardinality(String) COMMENT 'Aircraft Tail Number for Diverted Airport Code5'
)
ENGINE = MergeTree
PARTITION BY toYear(FlightDate)
ORDER BY (FlightDate, Reporting_Airline, OriginAirportID, DestAirportID, Flight_Number_Reporting_Airline, Tail_Number)
SETTINGS index_granularity = 8192
